const SALARY_STORE_NOTES={"rg12":"花花余假1天（未匹配到员工，疑为昵称）"};// 督导巡店：内置茹菓产品品质稽核标准（物料/卫生/服务三维度 + 红线项）；瑞幸/霸王标准待录入
const AUDIT_STD={"茹果奶茶":{"fullScore":100,"redlines":[{"code":"","item":"1.是否存在背后议论顾客，和顾客发生言语冲突，肢体冲突问题,是否出现服务态度恶劣，不理睬顾客,对于进店和离店顾客是否使有礼貌欢送用语等","method":"1.禁止出现争吵以及辱骂顾客行为； 2.禁止在店铺议论顾客 3.顾客进店询问，任何岗位人员都要回应顾客，切记不要出现不理会的现象等； 4.跟顾客沟通的时候，语调及肢体不可出现不礼貌行为，不可出现不耐烦的现象等； 5.如前台出现多位顾客等候，耐心服务当前顾客，及时安抚后面顾客，并告知等待时长，切记不能出现不告知不理会现象等"},{"code":"","item":"2.产品制作不得随意更改配方并且按照标准流程制作","method":"1.按照标准SOP进行产品制作"},{"code":"","item":"3.时效标签是否存在篡改日期行为； 报损是否按真实日期填写；","method":"1.水果及物料到货按真实日期填写 2.到店货物（味全，卡士，牛奶）不允许超过一周 3.过期和变质发霉食品严禁使用"},{"code":"","item":"4.严禁在店铺传播负能量，影响店铺氛围。","method":"1.店铺禁止对外议论任何人"},{"code":"","item":"5.前台不得擅自离岗,如需离岗做好岗位交接,操作台内禁止出现嘻哈,打闹或无人在岗的现象;","method":"1.吧台内的言行举止是否符合标准.不得在吧台内追逐，大声嬉笑打闹，影响门店形象 2.不得在吧台区域玩手机吃零食或换工作服 3.员工于操作区接打私人电话、饮食、娱乐等行为 4.正对食品打喷嚏、咳嗽等让食品受到污染的行为"},{"code":"","item":"6.小程序和各平台外卖产品10.00之前准时上架，营业时间内不可随意下架产品，如遇特殊情况请提前在群里报备(21.00前不可出现无故下架或不报备下架产品）。在营业时间内不允许私自关外卖。","method":"1.新品上架前进行外卖编辑，需要正确规范编辑，进行外卖检查。 2.每天10.00之前准时上架，不得出现漏上架或不上架现象 3.晚上21.00后根据实际情况陆续下架产品（手作产品除外） 4.在营业时间内，不允许私自关外卖，如遇特殊原因需报备说明"},{"code":"","item":"7.各项平台差评占比率率不得高于0.05%","method":"1.小程序,美团外卖，饿了么，抖音，美团团购,大众点评等 门店中差评占比率 =门店当月新增的与“口味”、“服务”和“出品”相关的中差评条数总和/门店当月订单数。 “中差评”定义为在平台评价中出现评分三星及以下的评价。 “口味”、“服务”和“产品”中差评的定义分别为： “口味中差评”：口味不一致、茶味淡、奶味淡、茶味浓、奶味浓、甜度淡、甜度浓等与口味相关的评价。 “服务中差评”：出餐久、出餐流程慢、"},{"code":"","item":"8.售后占比率不得高于总单量0.2%","method":"1.门店及线上客服售后数据统计（客观原因：小料添加出现问题、杯型做错、温度做错、吸管问题、包材质量问题、打包问题、包装不符或配料有问题等与产品出品有关的售后情况统一计算）"},{"code":"","item":"9.服务投诉:线上及线下","method":"1.1-3000单以内1条，5000单以内2条，8000以内3条，10000单以内4条 (责任判定以客观的事实为依据)"},{"code":"","item":"10.沙冰机,果酱机使用标准","method":"1.沙冰壶:每次搅拌时容量不可超过2杯（禁止） 2.果酱壶:每次盛装物料不可超过总容量的60%(总容量不能超过1500毫升) 3.放入沙冰机杯子需垂直向下放置，确定连接底座无松动方可使用，沙冰机运转完后需等待机器停止平稳在取杯，避免蘑菇头损坏"},{"code":"","item":"11.芒果汁调兑标准","method":"1.新鲜芒果汁搅拌过滤后出芒果汁 2.芒果汁,椰奶按比例调兑好后,必须用搅棒充分搅拌均匀(禁止吧勺搅拌)"},{"code":"","item":"12.水果存放标准","method":"1.水果进入冰箱存放时,外围需离杆,四周需离壁,避免压伤或冻坏 2.部分水果由于特性需按标准方法存放后至成熟使用,存放过程中不可出现过多损耗或人为导致损坏. (如芒果未返烧心,桃子,芭乐,猕猴桃,奇异果,新鲜牛油果捏伤等现象)"},{"code":"","item":"13.服务核心四大原则","method":"顾客第一 1.前台点单同事如果备料或者忙，规定10s回头往收银台回望，第一时间接触顾客打招呼。 2.外场服务：注意力一定是在顾客身上，顾客提出问题时，及时说不好意思，先给顾客解决问题，最后感谢顾客的反馈和建议。 3.目光注意力时刻在顾客身上，遇到顾客上前咨询一定当场解决顾客疑虑，或者当顾客抱怨时第一时间进行安抚，并了解情况进行解决。 及时招呼 1，目光接触，及时跟顾客打招呼微笑。 2.前台出现三批"},{"code":"","item":"14.证件齐全","method":"1.所有营业执照有效，小餐饮许可证在有效期内，店铺员工必须持证上岗，健康证需在有效期内（老员工提前一个月办理，新员工，兼职一周内办理到位） 2.未按要求公示在消费者可见区域。 3.门店员工健康证是假证、行业类别不是食品/餐饮等视为无效。"},{"code":"","item":"15.门店客服机畅通","method":"1.保证门店客服机能正常使用，保证电量有电 2.店铺电话不允许出现停机或关机状态 3.顾客找到我们这边，无论什么事，我们每个人都有责任，要主动帮助顾客去解决，不要推脱，多换位思考。"},{"code":"","item":"16.损害门店利益（保密制度）","method":"1.员工不得做出损坏店铺利益,形象和名声的任何行为,如有查实直接予以严厉处罚并开除;未经许可禁止将店铺机密透露给非工作其它人员,本店所有饮品配方等商业资料,不得拍照,复印,抄写等任何形式擅自保存,不得私自携带离开,不得提供货物给任何第三方.携带机密资料离开公司的,视情节及后果给予警告,开除并追究其相关法律责任; 2.本店所有经营收入情况资料及数据,不得提供或泄露给任何第三方,违者追究相关法律责任;"},{"code":"","item":"17.交叉污染","method":"1.水槽严禁洗拖把，地刮，下水道部件、隔渣池，私人物品（工服，饭碗等）"},{"code":"","item":"18.食品物料存储、摆放不符合要求，且未按先进先出使用原则","method":"1.食品/包材储存在潮湿、溅水、脏污的区域以及直接放在地上。 2.物料没有分类摆放整齐，没有先进先出使用，造成批量物料过期"},{"code":"","item":"19.批量产品操作失误","method":"1.如；腌制比例不精准(糖加成盐,或者白糖油,VC粉,木薯粉等), 2.果糖机校准失误 3.茶汤比例不精准 4.水果未达到使用标准"},{"code":"","item":"20.门店叫货出错","method":"1.周一到周四截止16：00，周五到周六截止17：00，节假日截止到19：00，禁止加减货 2.门店货物叫多或叫少需由门店分配处理"},{"code":"","item":"21.打卡规则","method":"1. 门店严禁一切代打卡行为，一经发现，将对双方当事人进行严肃处理。 2. 针对临时排休人员，一律禁止进行打卡操作。凡临时安排休息的员工，当日打卡记录一律作废，不核算任何工时与薪资，杜绝出现休班却正常计薪的考勤异常情况。（一经发现从重处理）"},{"code":"","item":"A:检查温度计使用标准：","method":"1、使用温度计达标；（电子温度计温度在0±0.3℃，机械温度计温度应正对0℃）； 2、温度计使用、读数正确无误差；"},{"code":"","item":"B:检查伙伴是否在30秒内完成茶汤过滤，以及搅拌动作","method":"1、闷泡时间不足直接过滤茶汤、超过30秒未滤出茶汤（计时器响后30秒内滤出）； 2、搅拌均匀：茶汤加入冰块后使用搅棒，搅拌均匀且至冰块完全融化（不可直接将冰捞出）"},{"code":"","item":"C:店铺到货是否在30分钟内搬到仓库，按照物料储存标准摆放","method":"1.是否堆放整齐，物料按照离地10公分标准存放。 2.仓库开封物料，是否按照储存标准保存。（附上时效期）"},{"code":"","item":"D:工作服是否穿戴整齐。","method":"1.帽子、发帽、工服、围裙、每天需更换清洗，保持洁净状态 2.进入吧台是否正确佩戴口罩以及单手佩戴手套（早上备料需双手配套手套） 3.不允许佩戴戒指，手镯，项链，手表以及夸张的耳饰等 ，不允许做美甲"},{"code":"","item":"E：前台，打包台，大厅不可出现堆放杂物或摆放凌乱的现象；","method":"1.大厅不可堆放：扫帚，拖把及桶，拖车，空框，纸壳，玻璃刷等 2.收银台：台卡，杯架，纸巾盒，展示盒（可放置） 3.打包台：吸管架，杯套盒，易撕贴（打包贴纸）（可放置）"},{"code":"","item":"F：水果以及半成品是否存在过期使用现象;备料和备货是否合理","method":"1.备料人员是否明确告知果切台同事备料数量！不得出现盲目备料的现象！ 2.是否根据实际情况叫货,是否存在备货过多，出现超期，产生损耗现象. (水果储存不得超出最佳赏味期:如橙子常温3天,冷藏5天等) 3.备料需根据实际情况,不得超过最佳时效期（半成品时效期：如橙子角5小时 ，桑葚10小时等)"},{"code":"","item":"G.工作群,店长群，群里发布的任何信息，(公司所传达的工作内容)，需要仔细阅读清楚明白并传达反馈","method":"1.阅读清楚明白后群里回复并进行传达店铺，同时需要给予反馈结果. 2.不可出现漏传或不传达的现象"},{"code":"","item":"H.美团，饿了么，大众点评，美团团购,抖音团购评价根据实际情况合理回复；平台评分时刻保持4.8分及以上（大众点评除外）","method":"1.评价需当天或次日回复。外卖紧急消息第一时间回复，并明确告知同事消息情况. 2.回复步骤：一：道歉，二：给出解决方案，三：解释原因（如出现有文字评价类容，需针对性回复，不得出现文不对题或者一致模板回复）"},{"code":"","item":"I.排班打卡规则","method":"1.员工之间如需私自换班，必须提前向店长报备，并征得同意，未经审批的私自换班一律不予认可，若产生考勤异常由本人自行承担。（店长需上报给督导）"}],"groups":[{"dim":"物料品质","items":[{"code":"Q1.1","item":"检查水果半成品是否符合标准","score":5,"method":"1、清洗步骤是否标准; 2、成熟度是否合格； 3、切制大小符合标准/均匀；（芒果丁：0.5cm³；粗吸管可吸起） 4、果肉状态不可出现过熟或未成熟，氧化发黑变软严重； 5、榴莲解冻后需仔细检查方可使用，避免出现榴莲果核，异物，生榴莲"},{"code":"Q1.2","item":"检查芝士奶盖是否符合标准","score":5,"method":"1、成品奶盖表面细腻光滑、有堆叠感； 2、不可出现表面粗糙，有明显颗粒感，有肉眼可见气泡； 3、奶盖状态过稀或过干，无堆叠感或流动性差，视为不标准；"},{"code":"Q1.3","item":"检查板栗，芋泥，米麻薯,珍珠,山楂,糖油等半成品是否符合标准","score":5,"method":"1.制作流程是否标准; 2.成品状态是否合格; 3.口感是否存在异常; 4.储存方式是否标准; 5.板栗，芋泥搅打状态为顺滑，无颗粒状"},{"code":"Q1.4","item":"检查蒟蒻/爆珠是否符合标准","score":1,"method":"1、检查成品蒟蒻的完整度，不可出现漏气和变质的现象 2、蒟蒻，爆珠需将糖水沥干清洗后使用"},{"code":"Q1.5","item":"检查西柚粒,茶冻是否符合标准","score":3,"method":"1、检查成品西柚的完整度，不可出现变味的现象； 2、成品茶冻不能出现水化不成形； 3、茶冻形状不能过大（吸管可吸入大小）"},{"code":"Q1.6","item":"检查冰块厚度标准","score":3,"method":"1、检查冰块未处于8-10g，冰块完整度需达到80%；"},{"code":"Q2.1","item":"检查茶叶开封后是否严格密封保存","score":2,"method":"1、袋装茶叶类开封使用后是否挤出袋内空气用封口夹封存；"},{"code":"Q2.2","item":"检查茶叶、水、冰块准确称量，操作中有使用温度计并测量水温；符合泡茶标准（茶叶、水、冰块及水温请参考产品SOP）","score":5,"method":"1、称量：茶叶、冰块使用电子秤称量，称量前正确清零； 2、温度：根据茶叶属性及最佳温度（茉莉茶71-73度，栀香绿茶71-73度，红茶95度以上）进行泡制，使用温度计测量水温；开水机接出热水如温度达不到需使用电磁炉煮沸后测温量取再使用；"},{"code":"Q2.3","item":"检查成品茶汤及储存是否符合标准","score":3,"method":"1、观察茶汤内不能出现异物、茶渣、茶叶残留； 2、茶汤是否放置保温桶冷藏储存使用； 3、是否贴上效期;"},{"code":"Q2.4","item":"检查产品口感试饮","score":3,"method":"1、试饮门店水果茶（标准冰标准糖）； 2、试饮结果是否达标（通过稽核部伙伴进行评测）； 3、如饮品不达标，需现场进行反推制作细节，并分析原因，做重点辅导；"},{"code":"Q2.5","item":"产品操作","score":3,"method":"1、漏糖，多加或漏加小料 2、杯型做错 3、温度出错 4、半成品物料加错"},{"code":"Q3.1","item":"外卖回复精准度","score":3,"method":"1、在回复外卖平台上的问题时，需要认真读懂顾客所问的疑问，不要出现同一模板，文不对题等现象"},{"code":"Q3.2","item":"杯套不剪","score":3,"method":"1、杯套每周一带到办公室并在杯套表上画“√”，不得出现杯套数量核对不上的状况 2、不得出现杯套未剪断的情况"},{"code":"Q4.1","item":"最新SOP技能熟悉程度考核","score":3,"method":"1、随机抽取2名门店伙伴（茶饮师及以上岗位） 2、考试范围为最新SOP技能：茶汤1款，产品类1款，抽背伙伴需说出完整操作流程，注意细节描述； （打分细则：参数错一个此项不得分，操作细节错误≥2个此项不得分）"}]},{"dim":"卫生标准","items":[{"code":"1","item":"文件管理","score":1,"method":""},{"code":"1.1","item":"进货单","score":1,"method":"门店所有货物(食品物料,包材,水果,耗材等)进货单保留24个月"},{"code":"1.2","item":"文件记录","score":1,"method":"门店需有记录留档(制冰机的门店端周清记录及虫害消杀记录)"},{"code":"2.1","item":"人员健康","score":1,"method":"1)无易感染(喷嚏,持续咳嗽,咽喉炎,发烧)或传染症状(呕吐,腹泻),无开放性皮肤症状(包括刀伤,烧伤 ,抓伤,脓肿,出血等） 2）手部有伤口时没有使用亮色（不可用肉色）创可贴及佩戴手套。"},{"code":"2.2","item":"人员着装","score":3,"method":"1）穿戴工服（T桖，围裙)工帽,深色长裤,口罩,并穿戴包裹脚趾,脚跟的深色防滑鞋;员工须佩戴发 帽,头发不得露出;所有衣物不得带有易脱落的装饰（包括且不限于水钻，珍珠，及亮片等） 2）工服，围裙无明显污垢，无异味，工服无松脱或已脱落的口子，线口，若衣物掉色，破损严重及时更换 3）不得留长指甲，涂指甲油或戴假指甲，不得佩戴饰物（戒指，手镯，耳环等 ） 4）不得穿短裤，裙子，拖鞋等，严重损害店铺形象（"},{"code":"2.3","item":"洗手消毒","score":1,"method":"1)每次进入吧台前必须先洗手.（配置专用毛巾擦手） 2）接触食品时未佩戴一次性手套。"},{"code":"2.4","item":"私人物品","score":1,"method":"1）个人水杯为不易碎材质，带盖，存放固定非工作区域（指定区域存放） 2）不允许员工在食品加工区域进行与 工作无关操作（如吃喝，吸烟，使用手机，拍照和接打私人电话，玩游戏等） 3）个人物品有独立存放区域，不得出现在食品加工，销售区域，不得与货品混放"},{"code":"2.5","item":"员工技能","score":1,"method":"1）员工对产品制作（如茶汤，小料，水果等）流程熟悉并严格按照标准化，表达流畅 2）设备清洗频率及流程，认知清楚，表达流畅 3）员工对于清洗消毒流畅：清洁消毒对象，方法，频率认知清楚，表达流畅"},{"code":"3.1","item":"合理存放","score":1,"method":"1）分类区分存放：食品，器具，清洁用具分别隔离存放，无混放：成品，半成品，原料不能混放：清洗过的器具，工具，抹布与未清洗过的分开倒立存放 2）食品包装开封后，需分装在不锈钢或塑料有盖容器中，所有食品存放过程中应加盖或密封；（贴上开封日期） 3）包装原料和冷冻制品放入冰箱（柜）时需去除外包装（纸箱及塑料袋）。"},{"code":"3.2","item":"仓库环境","score":1,"method":"1）仓库保持干燥，干净整齐，不得出现积水，漏水，霉变等现象"},{"code":"3.3","item":"货架","score":1,"method":"1）仓库货架无锈迹，无污渍；物料盛装容器（如塑料箱等二次包装容器）清洁，确认无污渍，无异味"},{"code":"3.4","item":"储物柜","score":1,"method":"1）水槽下方及其他储物柜干净无污垢，货物整齐码放；水槽下方不允许存放已开封干货物料（如茶叶，椰子粉，白砂糖等）避免受潮污染。"},{"code":"3.5","item":"储藏规范","score":1,"method":"1）冰箱内存放物料不得堵塞出风口 2）仓库货物堆叠不得过高，所有物料均离地10公分存放"},{"code":"3.6","item":"先进先出","score":3,"method":"1）食品物料（包括解冻物料，开封物料）须附上正确的时间条，并注明解冻，开封，制备及到期的时间日期 ，所有移去原包装的食品必须有标注名称，生产日期，保质期，密闭保存 2）所有物料执行先进先出：根据时间标签，执行先进先出，且不可在同一物料上张贴不同时间的标签"},{"code":"3.7","item":"储藏温度","score":1,"method":"1）水果冷藏柜中心温度不可超过6-8度，冷冻冰箱物料中心温度-10—-18度以下（晚间不开门期间恒温达到-18度）；非门封条破损，出风口堵塞，设备未开启及设备温度设定不正确导致物料温度超标 2）小料台上冷藏物料温度均保持0度-10度之间"},{"code":"3.8","item":"解冻流程","score":1,"method":"1）冷冻物料解冻方式正确且均在原包装内解冻 2）已解冻物料不可复冻.不可用水泡着解冻"},{"code":"4.1.1","item":"店铺外观","score":1,"method":"1）店铺招牌灯箱，ＫＴ板，充电宝，菜单屏等完整无破损，无污渍 2）门口处干净，无垃圾，无污渍，地垫干净，无破损 3）门店用品（电视机，充电宝，平板，手机等）正常使用，无积灰，无污渍"},{"code":"4.1.2","item":"店铺内部","score":2,"method":"1）客休区桌椅摆放整齐，及时清理台面，天花板干净无破损，无积灰，蜘蛛网。通风设备干净无破损，没有积灰。地面 清洁，无垃圾，水渍，茶渍 2）食品加工区地面清洁无垃圾，水渍，茶渍 3）操作区，备料区，客座区墙面，天花板不可有污渍，老化，脱落，发霉迹象 4）操作区如有门帘，需保持门帘清洁，无破损，无明显污渍"},{"code":"4.1.3","item":"垃圾桶","score":1,"method":"1）垃圾桶需搭配垃圾袋使用，垃圾桶不得存放过夜垃圾，垃圾桶需加盖垃圾箱外观干净无污渍，没有破损（每日清洁擦拭消毒）"},{"code":"4.1.4","item":"收银岗","score":2,"method":"1）收银台整洁不凌乱，台面无污渍，无杂物，（仅限于摆放台卡，杯架，食品展盒，电脑）"},{"code":"4.1.5","item":"打包区","score":2,"method":"1）打包区域干净，包装品盛放容器干净无异物 2）规定打包毛巾叠好放整齐，只允许放打包专用抹布（蓝色专用）"},{"code":"4.1.6","item":"制茶岗","score":2,"method":"1）台面，茶桶架，量杯架整洁，工具设备齐全，按要求摆放有序，干净卫生，无污渍，无积垢 2）冰槽使用后随时关门，冰槽内干净无污垢，无异物，冰块需超过1/2 3）水槽壁及底部无明显茶渍，积垢 4）上下水设备无锈迹，无破损，无渗透，干净无污渍"},{"code":"4.1.7","item":"果切台","score":2,"method":"1）果切台地面，台面，置物架干净整洁，设备器具按要求摆放有序，干净卫生，无污渍，无积垢 2）水槽出口配备须金属过滤网使用，水槽壁及底部无明显茶渍，积垢或泛黄现象 3）上下水设备无锈迹，无破损，无渗透，干净无污渍"},{"code":"4.2.1","item":"封口机","score":1,"method":"1）封口机外表干净无污渍,卡槽内干净卫生 2)封口机刀口干净无污渍,无锈迹"},{"code":"4.2.2","item":"奶昔机","score":1,"method":"1)奶昔机外表整洁,无奶渍 2)卡扣,刀片无变形且干净没有奶垢 3)奶昔机电机正常,档位正常,转速正常"},{"code":"4.2.3","item":"果糖机","score":1,"method":"1)果糖机外表干净无污渍 2)出糖口无结块,无堵塞,克数差异2克 3)果糖机内部无异物"},{"code":"4.2.4","item":"冷藏冰箱","score":1,"method":"1)冷藏冰箱温度显示正常(6-8度),外表干净无污渍，冷藏内无冷凝水 2)门封条,沟槽,层架完整无损坏,无霉斑,无积垢冷藏冰箱内不得有结霜，冷冻柜结霜厚度小于1cm 3)内部出风口没有物体遮挡,没有积灰积垢 4)内部干净无污渍,无异味 5)底部接水盘水位正常,没有溢出 6)严禁放私人物品（包含员工带的饭等）"},{"code":"4.2.5","item":"冷冻冰箱","score":1,"method":"1)冷冻冰箱温度显示正常(－10-－18度以下)外表干净无污渍, 2)冷冻设备内无冷凝水,冷冻冰箱物料无解冻现象,冷冻柜结霜厚度小于1cm 3)内部物料摆放整齐,干净无异味"},{"code":"4.2.6","item":"制冰机","score":1,"method":"1)制冰机外表干净无污渍 2)制冰机内不可出现红色霉菌 3)内部干净无污渍,冰块无异物 4)柜门随手关闭,冰铲干净无污渍,并悬挂在挂钩上,柜门沟槽无积垢,无霉斑"},{"code":"4.2.7","item":"电磁炉","score":1,"method":"1)电磁炉加热面表面干燥,无积垢,出风口无积灰 2)电磁炉运行加热正常,电子屏显示正常 3)电磁炉使用时台面无积水"},{"code":"4.2.8","item":"蒸汽机","score":1,"method":"1)蒸汽机表面干净,蒸汽碰头表面无积垢 2)蒸汽机运行正常,电子屏显示正常 3)蒸汽机喷头探针干净无奶渍残留,无扭曲变形 4)蒸汽机需配备专用抹布,于随手清洁（灰色专用）"},{"code":"4.2.9","item":"沙冰机","score":1,"method":"1)沙冰机外观及底部干净整洁,沙冰壶刻度清晰无磨损 2)不使用时内部干净无食品残留 3)沙冰壶底部旋转刀片无污垢残留，无异响现象 4)设备能正常运行,盖子可紧闭,无漏电现象"},{"code":"4.2.10.","item":"净水器","score":1,"method":"1)净水器外表清洁,密闭完好,无渗透现象 2)净水器滤芯褐变适中,所有滤芯在效期内,并附带时间条，定期更换"},{"code":"4.2.11","item":"开水机","score":1,"method":"开水机外表面干净无污垢"},{"code":"4.3.1","item":"工器具","score":1,"method":"1)工器具干净整洁不,无破损,无生锈,无异味且不可以它用 2)门店不可使用木制或竹制生产工具（木制，竹制材料易损坏霉变） 3）清洁用具（扫帚，拖把，百洁布，清洁用毛刷）需单独统一存放，不允许出现在食品操作台面及以上区域"},{"code":"4.3.2","item":"器具","score":1,"method":"1）储存食品容器或包装材料无破损，无生锈且不可以它用 2）未使用器皿干净无积垢，无异味，倒扣存放"},{"code":"4.3.3","item":"雪克杯","score":1,"method":"1)雪克杯数字刻度清晰,杯壁无明显茶垢,无破损 2)雪克杯不使用时倒扣放置"},{"code":"4.3.4","item":"茶桶","score":1,"method":"1)茶桶内外部干净无污渍,无茶垢,无破损 2)出水口干净无剩余茶汤 3)茶桶加盖放置,茶桶架无积垢"},{"code":"4.3.5","item":"量杯量壶","score":1,"method":"1)量杯量壶数字刻度标识清晰可见,无损坏,无茶垢 2)量壶加盖放置;杯架干净无茶渍,无积垢"},{"code":"4.3.6","item":"小器具","score":1,"method":"1)制茶岗小器具每天需用开水及专用清洁品浸泡，后勤岗的小器具需沥干存放 2小器具定点摆放，维护完好无破损，清洁干净无污渍，无茶垢"},{"code":"4.3.7","item":"抹布","score":3,"method":"1）抹布按区域分色使用，分色清洗，消毒，1个月需更换一次。 2）门店抹布采用不掉毛，易吸水，不易损坏的材质 3）清洁抹布应单独存放在后勤岗固定位置 4）所有抹布无破损，无异味，无明显污渍"},{"code":"5.1","item":"水果储存","score":3,"method":"1）门店储存的水果不得出现腐烂，腐败，病变，生虫等食安问题，如出现需及时废弃"},{"code":"5.2","item":"物料制备","score":2,"method":"1）原料使用前需保持包装完整无异常（如包装出现破损则不可使用） 2）制备水果物料，全程佩戴手套，不得裸手直接接触果肉（严禁用手抓取任何食品，一律使用器皿完成） 3)物料转入容器前,保证容器干净,无异物"},{"code":"6.1","item":"应急药品","score":1,"method":"1）药箱内放置常用药品，如：创口贴，烫伤膏，碘酒等 2）保证药品都在有效期内，临近效期药品及时替换 3）药箱加盖单独隔离存放"},{"code":"6.2","item":"灭蝇灯","score":1,"method":"1）灭蝇灯正常开启发光 2）灭蝇纸张贴效期条并在效期内，且灭蝇纸上蚊虫不超过50%"},{"code":"6.3","item":"风幕机","score":1,"method":"1）风幕机正常开启，出风口没有明显积灰"},{"code":"6.4","item":"化学药品","score":1,"method":"1）化学药品（洗洁精，氧泡泡，柠檬酸，清洁剂等化学药品）统一定位于果切台下方柜子储存，不得存放在食品加工区域，使用完毕后，放回存放处 2）配置好的氧泡泡专用容器储存"},{"code":"6.5","item":"异物防范","score":3,"method":"1）已开封的食品（水晶粉，茶叶，西米等）需用亚克力密封箱密封储藏 2）包装材料（杯子）不用的器具等需倒扣或加盖 3）设施（糖机，蒸汽机，奶昔机等）、设备、器具未按照按标准加盖密封"}]},{"dim":"服务-A","items":[{"code":"","item":"进店招呼","score":5,"method":"顾客进店需礼貌主动招呼 | 判定:伙伴有招呼进店顾客即得分"},{"code":"","item":"积极响应顾客","score":5,"method":"推荐主打饮品&推荐顾客注册会员(告知会员福利) | 判定:伙伴告知顾客推荐饮品且同时向顾客推荐会员福利即得分，若缺少一项本项不得分"},{"code":"","item":"主动核餐","score":5,"method":"仔细核对产品名，温度，甜度，产品特殊口感提醒 | 判定:有关于口感的解释或者说明的部分得分"},{"code":"","item":"引导入座","score":5,"method":"点完单后,根据实际情况告知等待时长，小伙伴是否主动引导顾客入座 | 判定:告知等待时长，并有引导入座，得5分 (若无座位情况，向顾客解释说明即可)"},{"code":"","item":"产品核对","score":5,"method":"取茶时，主动核对顾客取单号(需要主动询问并查看顾客取餐号) | 判定:顾客取餐时，伙伴需主动核对顾客取餐号，若未主动核对，本项不给分"},{"code":"","item":"饮用时间","score":5,"method":"需告知顾客最佳饮用时间及方法 | 判定:顾客取茶后需提醒最佳饮用时间及方法、产品承诺"},{"code":"","item":"产品承诺","score":5,"method":"取茶时承诺顾客不满意可重做"},{"code":"","item":"好评邀请","score":5,"method":"产品递给顾客时邀好评 | 判定:开口邀好评得分"},{"code":"","item":"送宾语","score":5,"method":"顾客取茶离开后送宾语欢送 | 判定:送宾语."},{"code":"","item":"服务态度","score":10,"method":"顾客感受门店服务态度是否热情且主动 | 判定:1.服务态度热情且主动得10分 2.服务态度良好或未主动得5分 3.服务态度不好且不主动0分"}]},{"dim":"环境-B","items":[{"code":"","item":"环境维护","score":5,"method":"设施：招牌/灯具/门窗/玻璃/装饰物/桌椅/等设施维护良好，没有损坏 | 判定:良好未损坏即得分"},{"code":"","item":"客区干净整齐","score":10,"method":"店面客区整体卫生需干净整洁（头发/污垢/垃圾/纸屑/烟头等），桌椅摆放整齐。 （顾客离开客座区，第一时间收拾干净，桌椅归位摆放整齐） | 判定:顾客离店3分钟内需清理并清理干净"},{"code":"","item":"吧台内整洁","score":10,"method":"顾客观察到门店吧台内物料摆放杂乱、操作台奶渍，果汁或茶汤等未清洁（做完饮品后，及时收拾） | 判定:一经发现即扣分（须保持随手清洁）"},{"code":"","item":"门店杂物","score":3,"method":"门店物料纸箱、拖车、拖把，扫帚，员工私人物品等摆放在客区内 | 判定:一经发现即扣分"},{"code":"","item":"温度舒适","score":2,"method":"顾客进店感受门店温度是否舒适 | 判定:顾客主观感受门店温度是否舒适 （不再接受空调损坏、商场统一控制空调等报备）"}]},{"dim":"出品-C","items":[{"code":"","item":"制作效率","score":10,"method":"出餐速度(按照统一标准) | 判定:达到标准即可得分"},{"code":"","item":"按要求制作","score":3,"method":"出品是否加盖或封口，杯身干净、无饮品外漏的现象 | 判定:饮品杯身干净无撒漏且正确加盖"},{"code":"","item":"餐具配置正确且齐全","score":2,"method":"正确配齐餐具(吸管、纸巾，杯套，叉子等)且根据产品本身正确配置吸管型号或叉子，杯贴是否贴正 | 判定:/"}]},{"dim":"附加-D","items":[{"code":"","item":"试饮发放","score":5,"method":"向顾客发放试饮 | 判定:试饮发放，并收集反馈后即可得分"},{"code":"","item":"服务嘉奖","score":5,"method":"顾客深刻感受到门店伙伴的细微服务 | 判定:以顾客的亲身体验感受即是否得分"}]}]}};


/* ---------- storage helpers ----------
   Claude 环境优先使用 window.storage；本地服务器使用 /api/storage；
   直接打开 HTML 时回退到 localStorage，保证数据可以正常保存。 */
const STORAGE_PREFIX="store_profit_system:";

/* ===== 腾讯云开发 CloudBase 对接（渐进增强）=====
   ★ 用法：把下面 CLOUD_ENV 改成你的「云开发环境ID」即可启用多端共享 + 截图云存储。
     留空 = 完全走浏览器本地存储（行为和现在一样，不受影响）。
   ★ 启用前需在 CloudBase 控制台完成：①开启「匿名登录」②建数据库集合 kv（权限：所有用户可读写或仅登录可读写）
     ③开启云存储 ④把本页部署到 CloudBase 静态托管（HTTPS 域名下 SDK 才能用）。详见我给的部署文档。 */
const CLOUD_ENV=""; // 后端化版本使用 Java /api/storage + MySQL，本地不再连接 CloudBase
const CLOUD_KV="kv";           // 数据库集合名：每个数据键存为一个文档 {_id:key, value:...}
const CLOUD_DIR="expense/";    // 报销截图在云存储中的目录
let CLOUDAPP=null,CLOUDDB=null,CLOUD_OK=false,CLOUD_URLCACHE={};
async function cloudInit(){
  if(!CLOUD_ENV)return false;
  if(typeof cloudbase==="undefined"){console.warn("CloudBase SDK 未加载（需联网且在 HTTPS 域名下）");return false;}
  try{
    CLOUDAPP=cloudbase.init({env:CLOUD_ENV});
    await CLOUDAPP.auth().signInAnonymously();   // 匿名登录（控制台需开启）
    CLOUDDB=CLOUDAPP.database();
    CLOUD_OK=true; console.info("CloudBase 已连接：",CLOUD_ENV); return true;
  }catch(e){console.error("CloudBase 初始化失败，自动回退本地存储：",e);CLOUD_OK=false;return false;}
}
async function cloudUploadImg(dataURL){          // 报销截图：dataURL→上传云存储→返回 fileID（跨端可见、不占本地容量）
  if(!CLOUD_OK||!dataURL||!/^data:/.test(dataURL))return dataURL;
  try{
    const blob=await (await fetch(dataURL)).blob();
    const cloudPath=CLOUD_DIR+Date.now()+"-"+Math.random().toString(36).slice(2,8)+".jpg";
    const r=await CLOUDAPP.uploadFile({cloudPath,filePath:blob});
    return r.fileID||dataURL;
  }catch(e){console.error("截图上传失败，暂存本地：",e);return dataURL;}
}
async function cloudResolveImgs(records){        // 把列表里的 fileID 批量换成临时URL，缓存到 CLOUD_URLCACHE
  if(!CLOUD_OK)return;
  const ids=[...new Set(records.map(r=>r.img).filter(v=>typeof v==="string"&&v.indexOf("cloud://")===0&&!CLOUD_URLCACHE[v]))];
  if(!ids.length)return;
  try{const r=await CLOUDAPP.getTempFileURL({fileList:ids});(r.fileList||[]).forEach(f=>{if(f.tempFileURL)CLOUD_URLCACHE[f.fileID]=f.tempFileURL;});}
  catch(e){console.error("获取截图URL失败：",e);}
}
function cloudImgSrc(img){return (typeof img==="string"&&img.indexOf("cloud://")===0)?(CLOUD_URLCACHE[img]||""):(img||"");}

/* 列出浏览器本地存储里本系统的全部数据键（去掉前缀） */
function localDataKeys(){
  const keys=[];
  for(let i=0;i<localStorage.length;i++){
    const full=localStorage.key(i);
    if(full&&full.indexOf(STORAGE_PREFIX)===0)keys.push(full.slice(STORAGE_PREFIX.length));
  }
  return keys;
}
/* 一键把「现在浏览器里的本地数据」上传到云端（云端同名数据会被本地覆盖）。
   启用云端后云里是一份新的空/种子数据，此按钮用于把本机既有数据搬上云、实现多端共享。 */
async function cloudMigrateLocal(){
  if(!CLOUD_OK||!CLOUDDB){toast("云端未连接，无法迁移（需联网并在 HTTPS 域名下打开）");return;}
  const keys=localDataKeys();
  if(!keys.length){toast("本地没有可迁移的数据");return;}
  if(!confirm(`将把本地 ${keys.length} 项数据上传到云端：\n${keys.join("、")}\n\n云端同名数据会被本地数据覆盖，此操作不可撤销。确定继续？`))return;
  toast("正在迁移到云端…");
  let ok=0,fail=0;const failKeys=[];let firstErr="";
  for(const k of keys){
    try{
      const raw=localStorage.getItem(STORAGE_PREFIX+k);
      if(raw==null)continue;
      const val=JSON.parse(raw);
      await CLOUDDB.collection(CLOUD_KV).doc(k).set({value:val}); // 存为 {_id:k, value:...}，与 sSet 云端写入格式一致
      ok++;
    }catch(e){console.error("迁移失败："+k,e);fail++;failKeys.push(k);if(!firstErr)firstErr=(e&&(e.message||e.code))||String(e);}
  }
  if(fail){
    alert(`迁移完成：成功 ${ok} 项，失败 ${fail} 项（${failKeys.join("、")}）。\n\n失败原因（原文）：\n${firstErr}\n\n${cloudErrHint(firstErr)}`);
  }else{
    alert(`迁移成功：已把本地 ${ok} 项数据全部上传到云端。\n点击「确定」后将重新加载页面，从云端读取最新数据。`);
    location.reload();
  }
}
/* 把云端 SDK 的英文/代码错误翻成「问题在哪、怎么修」的中文提示 */
function cloudErrHint(msg){
  const m=(msg||"").toString().toLowerCase();
  if(m.includes("permission")||m.includes("denied")||m.includes("无权限")||m.includes("permit"))
    return "➤ 判断：数据库【写权限】被拒。\n修复：CloudBase 控制台 → 数据库 → 集合 kv → 权限设置 → 选「所有用户可读写」（或自定义规则 {\"read\":true,\"write\":true}）→ 保存后强刷重试。";
  if(m.includes("not exist")||m.includes("not found")||m.includes("collection")&&m.includes("exist"))
    return "➤ 判断：云数据库里没有名为 kv 的集合。\n修复：CloudBase 控制台 → 数据库 → 新建集合，名字填 kv（全小写）→ 再设权限为「所有用户可读写」→ 强刷重试。";
  if(m.includes("load")&&m.includes("url")||m.includes("cors")||m.includes("network")||m.includes("failed to fetch")||m.includes("安全域名")||m.includes("origin"))
    return "➤ 判断：请求被拦（多为【安全域名】未配置或网络问题）。\n修复：CloudBase 控制台 → 环境 → 安全配置/安全来源(Web安全域名) → 把当前浏览器地址栏的域名加进白名单 → 等1~2分钟 → 强刷重试。\n当前域名："+((location&&location.host)||"未知");
  if(m.includes("auth")||m.includes("login")||m.includes("token")||m.includes("匿名"))
    return "➤ 判断：登录态问题。\n修复：CloudBase 控制台 → 身份认证 → 开启【匿名登录】→ 强刷重试。";
  return "➤ 未能自动识别，请把上面这行「失败原因（原文）」发给协助你的人。";
}
/* 云端自检：做一次真实的写入+读取+删除，把结果用中文弹窗告诉你，不用开控制台 */
async function cloudSelfTest(){
  if(!CLOUD_OK||!CLOUDDB){alert("云端未连接：当前是本地存储模式。\n需通过 CloudBase 静态托管的 HTTPS 域名打开本页才会连云。");return;}
  const testId="__selftest__";
  try{
    await CLOUDDB.collection(CLOUD_KV).doc(testId).set({value:{t:"ok"}});      // 测试写
    const r=await CLOUDDB.collection(CLOUD_KV).doc(testId).get();               // 测试读
    const got=r&&r.data&&r.data[0]&&r.data[0].value&&r.data[0].value.t;
    try{await CLOUDDB.collection(CLOUD_KV).doc(testId).remove();}catch(_){}      // 清理（失败无所谓）
    if(got==="ok")alert("✅ 云端读写正常！\n数据库集合 kv 可读可写，现在可以放心点「一键迁移本地数据到云端」了。");
    else alert("⚠️ 写入成功但读回异常，可能是权限为「只写不可读」。\n建议把 kv 集合权限设为「所有用户可读写」。");
  }catch(e){
    const msg=(e&&(e.message||e.code))||String(e);
    alert("❌ 云端读写失败。\n\n原因（原文）：\n"+msg+"\n\n"+cloudErrHint(msg));
  }
}
/* 导出：把本机全部数据打成一个 .json 备份文件下载下来（任何模式都能用，含 file:// 本地打开） */
function exportLocalBackup(){
  const keys=localDataKeys();
  if(!keys.length){toast("本机没有数据可导出");return;}
  const dump={__type:"store_profit_backup",__count:keys.length};
  keys.forEach(k=>{ dump[k]=localStorage.getItem(STORAGE_PREFIX+k); }); // 原样保存 JSON 字符串
  const blob=new Blob([JSON.stringify(dump)],{type:"application/json"});
  const a=document.createElement("a");
  a.href=URL.createObjectURL(blob);
  a.download="门店数据备份.json";
  document.body.appendChild(a);a.click();document.body.removeChild(a);
  setTimeout(()=>URL.revokeObjectURL(a.href),1000);
  toast(`已导出备份（${keys.length} 项）：门店数据备份.json`);
}
/* 导入：读一个备份文件 → 连云时上传到云端 + 写本机；未连云时只写本机。 */
async function importBackup(input){
  const f=input&&input.files&&input.files[0]; if(!f)return;
  let dump;
  try{ dump=JSON.parse(await f.text()); }
  catch(e){ alert("文件读取失败，请选择用「导出备份」生成的 门店数据备份.json 文件。"); input.value=""; return; }
  const keys=Object.keys(dump).filter(k=>k.indexOf("__")!==0);
  if(!keys.length){ alert("这个备份文件里没有数据。"); input.value=""; return; }
  const toCloud=CLOUD_OK&&CLOUDDB;
  const where=toCloud?"云端（并同时写入本机）":"本机";
  if(!confirm(`将把备份里的 ${keys.length} 项数据导入到${where}，同名数据会被覆盖。确定继续？`)){ input.value=""; return; }
  toast("正在导入…");
  let ok=0,fail=0,firstErr="";
  for(const k of keys){
    try{
      const rawStr=(typeof dump[k]==="string")?dump[k]:JSON.stringify(dump[k]);
      const val=JSON.parse(rawStr);
      if(toCloud)await CLOUDDB.collection(CLOUD_KV).doc(k).set({value:val}); // 上传云端
      localStorage.setItem(STORAGE_PREFIX+k,rawStr);                        // 同时落本机
      ok++;
    }catch(e){ fail++; if(!firstErr)firstErr=(e&&(e.message||e.code))||String(e); }
  }
  input.value="";
  if(fail){
    alert(`导入完成：成功 ${ok} 项，失败 ${fail} 项。\n\n失败原因（原文）：\n${firstErr}\n\n${cloudErrHint(firstErr)}`);
  }else{
    alert(`导入成功：${ok} 项已${toCloud?"上传到云端并":""}写入本机。\n点「确定」后刷新页面生效。`);
    location.reload();
  }
}

async function sGet(k){
  try{
    if(CLOUD_OK&&CLOUDDB){
      try{const res=await CLOUDDB.collection(CLOUD_KV).doc(k).get();const d=res&&res.data&&res.data[0];return d?d.value:null;}
      catch(e){console.error("云端读取失败，回退本地：",e);}
    }
    if(window.storage&&typeof window.storage.get==="function"){
      const r=await window.storage.get(k,false);return r?JSON.parse(r.value):null;
    }
    if(location.protocol==="http:"||location.protocol==="https:"){
      try{
        const r=await fetch("/api/storage?key="+encodeURIComponent(k));
        if(r.ok){const d=await r.json();return d&&d.value!=null?JSON.parse(d.value):null;}
      }catch(_){/* API 不可用时继续使用浏览器本地存储 */}
    }
    const raw=localStorage.getItem(STORAGE_PREFIX+k);
    return raw==null?null:JSON.parse(raw);
  }catch(e){console.error("读取数据失败",e);return null;}
}
// 返回 true=已存入权威存储(云端/宿主/服务器)；false=仅暂存本机(服务器保存失败，已弹窗告警)
async function sSet(k,v){
  try{
    if(CLOUD_OK&&CLOUDDB){
      try{await CLOUDDB.collection(CLOUD_KV).doc(k).set({value:v});return true;}
      catch(e){console.error("云端保存失败，回退本地：",e);}
    }
    const value=JSON.stringify(v);
    if(window.storage&&typeof window.storage.set==="function"){
      await window.storage.set(k,value,false);return true;
    }
    // 通过后端打开时，服务器数据库才是权威存储：保存失败必须让用户知道，不能假装成功
    if(location.protocol==="http:"||location.protocol==="https:"){
      let serverErr=null;
      try{
        const r=await fetch("/api/storage",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({key:k,value})});
        if(r.ok)return true;
        serverErr="HTTP "+r.status;
      }catch(e){ serverErr=(e&&e.message)||"网络错误"; }
      localStorage.setItem(STORAGE_PREFIX+k,value); // 仍在本机留一份应急备份，避免直接丢数据
      console.error("服务器保存失败("+serverErr+")，已暂存本机：",k);
      toast("⚠️ 未能保存到服务器（"+serverErr+"），已暂存本机。请检查网络或后端后重试，勿关闭页面");
      return false;
    }
    // 直接以 file:// 打开时本机存储即为主存储，正常返回
    localStorage.setItem(STORAGE_PREFIX+k,value);
    return true;
  }catch(e){console.error(e);toast("保存失败，请重试");return false;}
}

/* 操作日志（本地） */
async function logOp(type,dataType,sid,month,prev,next,reason){
  const s=STORES.find(x=>x.id===sid);
  LOGS.unshift({
    at:new Date().toISOString(), by:CURRENT_USER, type, dataType,
    store:s?s.name:(sid||""), month:month||"",
    before:prev?JSON.stringify(prev):"", after:next?JSON.stringify(next):"", reason:reason||""
  });
  if(LOGS.length>500)LOGS.length=500;
  await sSet("logs",LOGS);
}

